sendEmail = async ({ to, subject, html }) => {
  if (!transporter) {
    console.log(`[EMAIL] To: ${to} | Subject: ${subject}`);
    console.log(`[EMAIL] Body: ${html}`);
    return { messageId: 'console-fallback' };
  }

  const info = await transporter.sendMail({
    from: `"Zilla" <${env.FROM_EMAIL}>`,
    to,
    subject,
    html,
  });

  return info;
}

