getStoredUser = () => {
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');
  if (!token || !role) {
    return null;
  }

  const storedUser = localStorage.getItem('user');
  if (!storedUser) {
    return { token, role };
  }

  try {
    const parsedUser = JSON.parse(storedUser);
    return {
      ...parsedUser,
      name: parsedUser.full_name || parsedUser.name || '',
    };
  } catch {
    return { token, role };
  }
}

