  await query(
    'UPDATE users SET otp_code = $1, otp_expires_at = $2 WHERE email = $3',
    [otp, otp_expires_at, email]
  );

  notificationService.sendOTP(email, otp);

  return { message: 'If an account with that email exists, an OTP has been sent.' };
}

